if (state.node.count === undefined) {
    state.node.count = 0;
}

const timestamp = simDate();
const printerId = simPrinterId();
const model = simModel();

const simulatedPrinterEvent = {
    eventId: (model + "_" + printerId + "_" + timestamp),
    printerId,
    brand: simBrand(),
    model,
    type: simType(),
    paper: simPaper(),
    sided: simSided(),
    color: simColor(),
    sheets: simSheets(),
    inkLevel: simInkLevel(),
    status: simStatus(),
    timestamp,
};

state.node.count++;

// 20% duplicates
if (state.node.count % 5 === 0) {
    await push(simulatedPrinterEvent);
}

// Some events are invalid
if (state.node.count % 10 === 3) {
    simulatedPrinterEvent.printerId = "invalidShouldBeInt";
    simulatedPrinterEvent.timestamp = "UNKNOWN";
    simulatedPrinterEvent.paper = "XYZ123";
}

await push(simulatedPrinterEvent);

function simBrand() {
    return "Acme";
}

function simModel() {
    if (printerId % 3 === 0) {
        return "MPS-Super";
    } else if (printerId % 2 === 0) {
        return "MPS-Ultra";
    } 
    return "MPS-Plus";
}

function simType() {
    return printerId % 2 === 0 ? "Laser" : "Ink";
}

function simPaper() {
    return state.node.count % 5 === 0 ? "A4" : "A3";
}

function simSided() {
    return state.node.count % 3 === 0 ? "Two" : "One";
}

function simColor() {
    return state.node.count % 2 === 0 ? "No" : "Yes";
}

// simulate timestamp to random time between now and 60 seconds ago
function simDate() {
    return new Date(Date.now() - Math.floor(Math.random() * 1000 * 60));
}

function simSheets() {
    return Math.floor(payload.value * 3.55);
}

// simulate 5 unique printers
function simPrinterId() {
    return ((payload.value-1) % 5) + 101;
}

function simInkLevel() {
    if (printerId % 4 === 0) {
        return 15;
    } if (printerId % 3 === 0) {
        return 50;
    } else {
        return 45;
    }
}

function simStatus() {
    return printerId % 3 === 0 ? "Needs service" : "Normal";
}

